class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def flatten(root: TreeNode) -> None:
    if not root:
        return

    flatten(root.left)
    flatten(root.right)

    temp_right = root.right

    if root.left:
        root.right = root.left
        root.left = None

        current = root.right
        while current.right:
            current = current.right

        current.right = temp_right
